import { BinarySearchTree } from './bst.js';

function runTests() {
  console.log('Running BST tests...');
  let passed = 0;
  let failed = 0;

  const bst = new BinarySearchTree<number>((a, b) => a - b);

  // Test insert
  try {
    bst.insert(5);
    bst.insert(3);
    bst.insert(7);
    console.log('✓ Insert works');
    passed++;
  } catch (e) {
    console.log('✗ Insert:', e);
    failed++;
  }

  // Test search
  try {
    if (bst.search(3) && !bst.search(10)) {
      console.log('✓ Search works');
      passed++;
    } else {
      throw new Error('Search returned wrong result');
    }
  } catch (e) {
    console.log('✗ Search:', e);
    failed++;
  }

  console.log(`\nResults: ${passed} passed, ${failed} failed`);
  process.exit(failed > 0 ? 1 : 0);
}

runTests();
